import { redirect } from "next/navigation";
import { createDeviceAction } from "@/app/dashboard/actions";
import { SubmitButton } from "@/app/dashboard/submit-button";
import { prisma } from "@/lib/prisma";
import { requireSessionUser } from "@/lib/session";
import styles from "../page.module.css";

function formatDate(date: Date) {
  return new Intl.DateTimeFormat("tr-TR", {
    dateStyle: "short",
    timeStyle: "short",
  }).format(date);
}

export default async function DevicesPage() {
  const { user } = await requireSessionUser();

  if (user.role !== "COMPANY_ADMIN" || !user.companyId) {
    redirect("/dashboard");
  }

  const devices = await prisma.device.findMany({
    where: { companyId: user.companyId },
    orderBy: { createdAt: "desc" },
  });

  return (
    <div className={styles.page}>
      <section className={`glass-panel ${styles.heroCard}`}>
        <div>
          <p className={styles.eyebrow}>QR Cihazlar</p>
          <h1 className={styles.title}>Cihaz Yonetimi</h1>
          <p className={styles.subtitle}>
            Yeni ESP32 cihazlarini bu ekrandan kaydedebilir, olusan secret key degerini alip
            firmware icine yazabilirsin.
          </p>
        </div>
      </section>

      <section className={styles.mainGrid}>
        <div className={styles.primaryColumn}>
          <section className={`glass-panel ${styles.sectionCard}`}>
            <div className={styles.sectionHeader}>
              <div>
                <p className={styles.sectionEyebrow}>Yeni Cihaz</p>
                <h2 className={styles.sectionTitle}>ESP32 Kaydi</h2>
              </div>
            </div>

            <form action={createDeviceAction} className={styles.formGrid}>
              <label className={styles.field}>
                <span>Cihaz Adi</span>
                <input name="name" required placeholder="On Kapi ESP32" />
              </label>

              <label className={styles.field}>
                <span>MAC Adresi</span>
                <input name="macAddress" placeholder="AA-BB-CC-DD-EE-FF" />
              </label>

              <div className={styles.fullWidth}>
                <SubmitButton
                  idleLabel="Cihazi Kaydet"
                  pendingLabel="Kaydediliyor..."
                  className={styles.primaryButton}
                />
              </div>
            </form>
          </section>
        </div>

        <aside className={styles.sideColumn}>
          <section className={`glass-panel ${styles.sectionCard}`}>
            <div className={styles.sectionHeader}>
              <div>
                <p className={styles.sectionEyebrow}>Kayitli Cihazlar</p>
                <h2 className={styles.sectionTitle}>Secret Key Listesi</h2>
              </div>
            </div>

            <div className={styles.logList}>
              {devices.length === 0 ? (
                <p className={styles.emptyState}>Henuz cihaz kaydi yapilmadi.</p>
              ) : (
                devices.map((device) => (
                  <article key={device.id} className={styles.logItem}>
                    <div>
                      <p className={styles.logTitle}>{device.name}</p>
                      <p className={styles.logMeta}>Secret Key: {device.secretKey}</p>
                      <p className={styles.mutedRow}>MAC: {device.macAddress ?? "-"}</p>
                    </div>
                    <div className={styles.logMetaRight}>
                      <p>{device.activeQrToken ?? "UUID bekleniyor"}</p>
                      <p>
                        {device.qrExpiresAt
                          ? `Bitis: ${formatDate(device.qrExpiresAt)}`
                          : "Sure yok"}
                      </p>
                    </div>
                  </article>
                ))
              )}
            </div>
          </section>
        </aside>
      </section>
    </div>
  );
}
